# Step 1: Analyze video duration
INPUT="input.mp4"

ffprobe -v quiet -print_format json -show_format "$INPUT" 2>&1 | node -e "
const d=require('fs').readFileSync('/dev/stdin','utf-8');
const j=JSON.parse(d);
const dur=parseFloat(j.format.duration);
const m=Math.floor(dur/60);
const s=Math.floor(dur%60);
console.log('File: '+j.format.filename);
console.log('Duration: '+dur+'s ('+m+'m '+s+'s)');
console.log('Interval: 30s');
console.log('Thumbnails to generate: ~'+Math.floor(dur/30));
"
